                                            _row[20] = row[orig_asym_id_col] = auth_asym_id
                                            _row[5] = row[comp_id_col] = auth_comp_id
                                            _row[18] = row[auth_comp_id_col] = auth_comp_id
                                            comp_id = auth_comp_id
                                            _seq_key = (seq_key[0], seq_key[1])
