                if conflict > 0 and (hasLargeSeqGap(_ps1, _ps2) or (hasLargeInnerSeqGap(ps1) and not hasLargeInnerSeqGap(ps2))):  # DAOTHER-7465
                    _ps1 = self.__compensateLadderHistidinTag2(chain_id, _ps2, _ps1)
