    def __parseNmrIf(self) -> bool:
        """ Parse NMRIF file.
        """

        if 'nmrif_file_path' not in self.__inputParamDict:

            err = f"No such {self.__inputParamDict['nmrif_file_path']!r} file."

            self.report.error.appendDescription('internal_error', f"+{self.__class_name__}.__parseNmrIf() ++ Error  - " + err)
            self.report.setError()

            if self.__verbose:
                self.__lfh.write(f"+{self.__class_name__}.__parseNmrIf() ++ Error  - {err}\n")

            return False

        if self.__nmrIfR is not None:
            return True

        fPath = self.__inputParamDict['nmrif_file_path']

        self.__nmrIfR = CifReader(self.__verbose, self.__lfh)

        try:

            if self.__nmrIfR.parse(fPath):
                return True

        except Exception:
            pass

        return False

    def __mergeCoordAsNmrIf(self) -> bool:
        """ Merge NMRIF metadata of the cooridnates (DAOTHER-8905: NMR data remediation Phase 2).
        """

        if len(self.__star_data) == 0 or self.__star_data[0] is None or self.__star_data_type[0] != 'Entry':
            return False

        if not self.__internal_mode or not self.__remediation_mode or self.report.getInputSourceIdOfCoord() < 0:
            return False

        master_entry = self.__star_data[0]

        self.__sf_category_list, self.__lp_category_list = self.__nefT.get_inventory_list(master_entry)

        if not self.__bmrb_only and self.__cR.hasCategory('entry'):
            entry = self.__cR.getDictList('entry')

            if len(entry) > 0 and 'id' in entry[0]:
                self.__entry_id = entry[0]['id'].strip().replace(' ', '_')

        ann = OneDepAnnTasks(self.__verbose, self.__lfh,
                             self.__sf_category_list, self.__entry_id)

        return ann.merge(master_entry, self.__cR, self.__bmrb_only and self.__internal_mode)

    def __mergeNmrIf(self) -> bool:
        """ Merge NMRIF metadata.
        """

        if len(self.__star_data) == 0 or self.__star_data[0] is None or self.__star_data_type[0] != 'Entry':
            return False

        if self.__nmrIfR is None or not self.__submission_mode:
            return False

        master_entry = self.__star_data[0]

        self.__sf_category_list, self.__lp_category_list = self.__nefT.get_inventory_list(master_entry)

        if not self.__bmrb_only and self.__nmrIfR.hasCategory('entry'):
            entry = self.__nmrIfR.getDictList('entry')

            if len(entry) > 0 and 'id' in entry[0]:
                self.__entry_id = entry[0]['id'].strip().replace(' ', '_')

        ann = OneDepAnnTasks(self.__verbose, self.__lfh,
                             self.__sf_category_list, self.__entry_id)

        return ann.merge(master_entry, self.__nmrIfR, self.__bmrb_only and self.__internal_mode)

    def __performBMRBAnnTasks(self) -> bool:
        """ Perform a series of standalone BMRB annotation tasks.
        """

        if len(self.__star_data) == 0 or self.__star_data[0] is None or self.__star_data_type[0] != 'Entry':
            return False

        # if not self.__submission_mode and not self.__internal_mode:
        #     return False

        master_entry = self.__star_data[0]

        self.__sf_category_list, self.__lp_category_list = self.__nefT.get_inventory_list(master_entry)

        if not self.__bmrb_only and self.__nmrIfR is not None and self.__nmrIfR.hasCategory('entry'):
            entry = self.__nmrIfR.getDictList('entry')

            if len(entry) > 0 and 'id' in entry[0]:
                self.__entry_id = entry[0]['id'].strip().replace(' ', '_')

        ann = BMRBAnnTasks(self.__verbose, self.__lfh,
                           self.__sf_category_list, self.__entry_id,
                           self.__annotation_mode, self.__internal_mode, self.__enforce_peak_row_format,
                           self.__sail_flag, self.report,
                           ccU=self.__ccU, csStat=self.__csStat, c2S=self.__c2S)

        if self.report.getInputSourceIdOfCoord() >= 0 and self.__cR.hasCategory('database_2'):

            sf_category = 'entry_information'

            database_code = self.__cR.getDictListWithFilter('database_2',
                                                            [{'name': 'database_code', 'type': 'str'}],
                                                            [{'name': 'database_id', 'type': 'str', 'value': 'BMRB'}])

            if len(database_code) > 0:
                derived_entry_id = database_code[0]['database_code']

                if not self.__internal_mode:
                    derived_entry_title = None

                    if sf_category in self.__sf_category_list:
                        sf = master_entry.get_saveframes_by_category(sf_category)[0]
                        derived_entry_title = get_first_sf_tag(sf, 'Title', None)

                    ann.setProvenanceInfo(derived_entry_id, derived_entry_title)

                elif not self.__bmrb_only:

                    if sf_category in self.__sf_category_list:
                        sf = master_entry.get_saveframes_by_category(sf_category)[0]
                        derived_entry_title = get_first_sf_tag(sf, 'Title', None)

                        if derived_entry_title in emptyValue:
                            dir_path = self.__cR.getDirPath()

                            if os.path.exists(os.path.join(dir_path, f'bmr{derived_entry_id}_3.str')):

                                is_done, _, star_data = self.__nefT.read_input_file(os.path.join(dir_path, f'bmr{derived_entry_id}_3.str'))

                                if is_done:

                                    try:

                                        _sf = star_data.get_saveframes_by_category(sf_category)[0]
                                        derived_entry_title = get_first_sf_tag(_sf, 'Title', None)

                                    except IndexError:
                                        pass

                            if derived_entry_title not in emptyValue:
                                set_sf_tag(sf, 'Title', derived_entry_title)

                        lp_category = '_Related_entries'

                        try:

                            lp = sf.get_loop(lp_category)

                            tags = ['Database_name', 'Database_accession_code']

                            if set(tags) & set(lp.tags) == set(tags):
                                related_entries = lp.get_tag(tags)

                                has_provenance = False
                                for idx, row in enumerate(related_entries):
                                    if row == ['BMRB', derived_entry_id]:
                                        has_provenance = True
                                        if derived_entry_title not in emptyValue:
                                            lp.data[idx][lp.tags.index('Relationship')] = derived_entry_title
                                        break

                                if not has_provenance:
                                    row = [None] * len(lp.tags)
                                    row[lp.tags.index('Database_name')] = 'BMRB'
                                    row[lp.tags.index('Database_accession_code')] = derived_entry_id
                                    if derived_entry_title not in emptyValue:
                                        row[lp.tags.index('Relationship')] = derived_entry_title
                                    row[lp.tags.index('Entry_ID')] = self.__entry_id

                                    lp.add_data(row)

                                    lp.sort_rows(['Database_name', 'Database_accession_code'])

                        except KeyError:
                            items = ['Database_name', 'Database_accession_code', 'Relationship', 'Entry_ID']

                            lp = pynmrstar.Loop.from_scratch(lp_category)

                            tags = [lp_category + '.' + item for item in items]

                            lp.add_tag(tags)

                            lp.add_data(['BMRB', derived_entry_id, derived_entry_title, self.__entry_id])

                            database_code = self.__cR.getDictListWithFilter('database_2',
                                                                            [{'name': 'database_code', 'type': 'str'},
                                                                             {'name': 'database_id', 'type': 'str'}])

                            if len(database_code) > 0:
                                for d in database_code:
                                    if d['database_code'] in emptyValue or d['database_id'] in emptyValue\
                                       or d['database_id'] in ('PDB', 'BMRB', 'WWPDB'):
                                        continue
                                    lp.add_data([d['database_id'], d['database_code'], None, self.__entry_id])

                            if len(lp) > 1:
                                lp.sort_rows(['Database_name', 'Database_accession_code'])

                            sf.add_loop(lp)

        if self.__op == 'nmr-cs-mr-merge' and self.__bmrb_only:
            cs_file_path_list = 'chem_shift_file_path_list'

            cs = self.__inputParamDict[cs_file_path_list][0]

            if isinstance(cs, str):
                cs_path = cs
            else:
                cs_path = cs['file_name']

            self.__c2S.set_entry_id(master_entry, self.__bmrb_id)
            self.__c2S.normalize_str(master_entry)

            master_entry.write_to_file(cs_path, show_comments=True, skip_empty_loops=True, skip_empty_tags=False)

        is_done = ann.perform(master_entry)

        if is_done:

            if self.__bmrb_only:
                input_source = self.report.input_sources[0]
                input_source_dic = input_source.get()

                file_type = input_source_dic['file_type']

                self.__sf_category_list, self.__lp_category_list = self.__nefT.get_inventory_list(master_entry)

                lp_counts = {t: 0 for t in NMR_CONTENT_SUBTYPES}
                for lp_category in self.__lp_category_list:
                    if lp_category in LP_CATEGORIES[file_type].values():
                        lp_counts[[k for k, v in LP_CATEGORIES[file_type].items() if v == lp_category][0]] += 1

                content_subtypes = {k: lp_counts[k] for k in lp_counts if lp_counts[k] > 0}

                input_source.setItemValue('content_subtype', content_subtypes)

            self.__depositNmrData()

        return is_done

    def __discardPeakListRemediation(self) -> bool:
        """ Distcard remediated spectral peak list (NMR data remediation, Phase 2) in OneDep enviromment
            @note: This rediculaus reverse implementation is for OneDep only
        """

        if self.__native_combined or not self.__merge_any_pk_as_is:
            return True

        if len(self.__star_data) == 0 or self.__star_data[0] is None or self.__star_data_type[0] != 'Entry':
            return False

        ar_file_path_list = 'atypical_restraint_file_path_list'

        if ar_file_path_list not in self.__inputParamDict:
            return True

        src_id = self.report.getInputSourceIdOfCoord()

        if src_id < 0:
            return False

        cif_input_source = self.report.input_sources[src_id]
        cif_input_source_dic = cif_input_source.get()

        has_poly_seq = has_key_value(cif_input_source_dic, 'polymer_sequence')

        if not has_poly_seq:
            return False

        file_type = 'nmr-star'
        content_subtype = 'spectral_peak'

        sf_category = SF_CATEGORIES[file_type][content_subtype]

        if sf_category not in self.__sf_category_list:
            return True

        modified = False

        for sf in self.__star_data[0].get_saveframes_by_category(sf_category):

            text_data = get_first_sf_tag(sf, 'Text_data')

            if text_data not in emptyValue:
                continue

            file_name = get_first_sf_tag(sf, 'Data_file_name')

            if file_name in emptyValue:
                continue

            for ar in self.__inputParamDict[ar_file_path_list]:
                file_type = ar['file_type']

                if file_type is None or not file_type.startswith('nm-pea'):
                    continue

                file_path = ar['file_name']
                original_file_name = ar['original_file_name'] if 'original_file_name' in ar else None

                if file_name in (os.path.basename(file_path), original_file_name):
                    data_format = get_peak_list_format(file_path)

                    if data_format is not None:

                        for lp in sf.loops:
                            if lp.category in ('_Peak_row_format', '_Peak', '_Peak_general_char', '_Peak_char', '_Assigned_peak_chem_shift'):
                                del sf[lp]  # What a waste!

                        set_sf_tag(sf, 'Text_data_format', data_format)

                        with open(file_path, 'r', encoding='ascii', errors='ignore') as ifh:
                            set_sf_tag(sf, 'Text_data', ifh.read())

                        modified = True

                    break

        if modified:
            master_entry = self.__c2S.normalize(self.__star_data[0])

            master_entry.write_to_file(self.__dstPath, show_comments=(self.__bmrb_only and self.__internal_mode), skip_empty_loops=True, skip_empty_tags=False)

        return True

    def __replaceCsSf(self) -> bool:
        """ Replace assigned chemical shift saveframe(s).
        """

        if len(self.__star_data) == 0 or self.__star_data[0] is None or self.__star_data_type[0] != 'Entry':
            return False

        master_entry = self.__star_data[0]

        has_chem_shift = False

        file_type = 'nmr-star'
        content_subtype = 'chem_shift'

        cs_files = []

        for fileListId in range(self.__cs_file_path_list_len):

            fileListId += 1

            input_source = self.report.input_sources[fileListId]
            input_source_dic = input_source.get()

            file_type = input_source_dic['file_type']
            file_name = input_source_dic['file_name']
            cs_files.append(f'{file_name!r}')

            if file_type != 'nmr-star':
                continue

            if input_source_dic['content_subtype'] is None:
                continue

            if content_subtype not in input_source_dic['content_subtype']:
                continue

            if self.__star_data_type[fileListId] not in ('Saveframe', 'Entry'):
                continue

            has_chem_shift = True

        if not has_chem_shift:
            err = f"There is no input assigned chemical shifts in {', '.join(cs_files)} file(s)."

            self.report.error.appendDescription('internal_error', f"+{self.__class_name__}.__replaceCsSf() ++ Error  - " + err)
            self.report.setError()

            if self.__verbose:
                self.__lfh.write(f"+{self.__class_name__}.__replaceCsSf() ++ Error  - {err}\n")

            return False

        sf_category = SF_CATEGORIES[file_type][content_subtype]

        removed_sf_framecode = []
        for sf in master_entry.get_saveframes_by_category(sf_category):
            removed_sf_framecode.append(sf.name)
            master_entry.remove_saveframe(sf.name)

        added_sf_framecode = []

        list_id = 1

        for fileListId in range(self.__cs_file_path_list_len):

            fileListId += 1

            input_source = self.report.input_sources[fileListId]
            input_source_dic = input_source.get()

            file_type = input_source_dic['file_type']

            if file_type != 'nmr-star':
                continue

            if input_source_dic['content_subtype'] is None:
                continue

            if content_subtype not in input_source_dic['content_subtype']:
                continue

            if self.__star_data_type[fileListId] not in ('Saveframe', 'Entry'):
                continue

            if isinstance(self.__star_data[fileListId], pynmrstar.Saveframe):
                self.__c2S.set_local_sf_id(self.__star_data[fileListId], list_id)

                added_sf_framecode.append(self.__star_data[fileListId].name)
                master_entry.add_saveframe(self.__star_data[fileListId])

                list_id += 1

            else:

                for sf in self.__star_data[fileListId].get_saveframes_by_category(sf_category):
                    self.__c2S.set_local_sf_id(sf, list_id)

                    added_sf_framecode.append(sf.name)
                    master_entry.add_saveframe(sf)

                    list_id += 1

        if list_id > 1:
            content_subtype = 'spectral_peak'

            sf_category = SF_CATEGORIES[file_type][content_subtype]

            for sf in master_entry.get_saveframes_by_category(sf_category):
                cs_framecode = get_first_sf_tag(sf, 'Chemical_shift_list')
                if cs_framecode in removed_sf_framecode:
                    idx = removed_sf_framecode.index(cs_framecode)
                    set_sf_tag(sf, 'Chemical_shift_list', added_sf_framecode[idx] if idx < len(added_sf_framecode) else None)
                else:
                    set_sf_tag(sf, 'Chemical_shift_list', None)

        return list_id > 1
